      paragrafos: [{"id":"eca:art-4-p1","numero":"1","texto":"A garantia de prioridade compreende:","alineas":[{"id":"eca:art-4-p1-a","numero":"a","texto":"primazia de receber proteção e socorro em quaisquer circunstâncias;"},{"id":"eca:art-4-p1-b","numero":"b","texto":"precedência de atendimento nos serviços públicos ou de relevância pública;"},{"id":"eca:art-4-p1-c","numero":"c","texto":"preferência na formulação e na execução das políticas sociais públicas;"},{"id":"eca:art-4-p1-d","numero":"d","texto":"destinação privilegiada de recursos públicos nas áreas relacionadas com a proteção à infância e à juventude."}]},{"id":"eca:art-4-p2","numero":"2","texto":"Compete aos pais, além de zelar pelos direitos de que trata o art. 3º desta Lei, prestar aos filhos assistência afetiva, por meio de convívio ou de visitação periódica, que permita o acompanhamento da formação psicológica, moral e social da pessoa em desenvolvimento.","alineas":[]},{"id":"eca:art-4-p3","numero":"3","texto":"Para efeitos desta Lei, considera-se assistência afetiva:","alineas":[]}],
