    {
      tipo: "artigo" as const,
      id: "eca:art-15",
      numero: "15",
      caput: "A criança e o adolescente têm direito à liberdade, ao respeito e à dignidade como pessoas humanas em processo de desenvolvimento e como sujeitos de direitos civis, humanos e sociais garantidos na Constituição e nas leis.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "eca:art-16",
      numero: "16",
      caput: "O direito à liberdade compreende os seguintes aspectos:",
      paragrafos: [],
      incisos: [{"id":"eca:art-16-inc-I","numero":"I","texto":"ir, vir e estar nos logradouros públicos e espaços comunitários, ressalvadas as restrições legais;","alineas":[]},{"id":"eca:art-16-inc-II","numero":"II","texto":"opinião e expressão;","alineas":[]},{"id":"eca:art-16-inc-III","numero":"III","texto":"crença e culto religioso;","alineas":[]},{"id":"eca:art-16-inc-IV","numero":"IV","texto":"brincar, praticar esportes e divertir-se;","alineas":[]},{"id":"eca:art-16-inc-V","numero":"V","texto":"participar da vida familiar e comunitária, sem discriminação;","alineas":[]},{"id":"eca:art-16-inc-VI","numero":"VI","texto":"participar da vida política, na forma da lei;","alineas":[]},{"id":"eca:art-16-inc-VII","numero":"VII","texto":"buscar refúgio, auxílio e orientação.","alineas":[]}],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "eca:art-17",
      numero: "17",
      caput: "O direito ao respeito consiste na inviolabilidade da integridade física, psíquica e moral da criança e do adolescente, abrangendo a preservação da imagem, da identidade, da autonomia, dos valores, idéias e crenças, dos espaços e objetos pessoais.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "eca:art-18",
      numero: "18",
      caput: "É dever de todos velar pela dignidade da criança e do adolescente, pondo-os a salvo de qualquer tratamento desumano, violento, aterrorizante, vexatório ou constrangedor.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "eca:art-18-A",
      numero: "18-A",
      caput: "A criança e o adolescente têm o direito de ser educados e cuidados sem o uso de castigo físico ou de tratamento cruel ou degradante, como formas de correção, disciplina, educação ou qualquer outro pretexto, pelos pais, pelos integrantes da família ampliada, pelos responsáveis, pelos agentes públicos executores de medidas socioeducativas ou por qualquer pessoa encarregada de cuidar deles, tratá-los, educá-los ou protegê-los.",
      paragrafos: [{"id":"eca:art-18-A-púnico","numero":"único","texto":"Para os fins desta Lei, considera-se:","alineas":[]}],
      incisos: [{"id":"eca:art-18-A-inc-I","numero":"I","texto":"castigo físico: ação de natureza disciplinar ou punitiva aplicada com o uso da força física sobre a criança ou o adolescente que resulte em:","alineas":[{"id":"eca:art-18-A-inc-I-a","numero":"a","texto":"sofrimento físico; ou"},{"id":"eca:art-18-A-inc-I-b","numero":"b","texto":"lesão;"}]},{"id":"eca:art-18-A-inc-II","numero":"II","texto":"tratamento cruel ou degradante: conduta ou forma cruel de tratamento em relação à criança ou ao adolescente que:","alineas":[{"id":"eca:art-18-A-inc-II-a","numero":"a","texto":"humilhe; ou"},{"id":"eca:art-18-A-inc-II-b","numero":"b","texto":"ameace gravemente; ou"},{"id":"eca:art-18-A-inc-II-c","numero":"c","texto":"ridicularize."}]}],
      referencias: [],
      historico: [{"versao":1,"texto":"A criança e o adolescente têm o direito de ser educados e cuidados sem o uso de castigo físico ou de tratamento cruel ou degradante, como formas de correção, disciplina, educação ou qualquer outro pretexto, pelos pais, pelos integrantes da família ampliada, pelos responsáveis, pelos agentes públicos executores de medidas socioeducativas ou por qualquer pessoa encarregada de cuidar deles, tratá-los, educá-los ou protegê-los.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.010, de 2014","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§único: Para os fins desta Lei, considera-se:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.010, de 2014","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. I: castigo físico: ação de natureza disciplinar ou punitiva aplicada com o uso da força física sobre a criança ou o adolescente que resulte em:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.010, de 2014","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"Inc. II: tratamento cruel ou degradante: conduta ou forma cruel de tratamento em relação à criança ou ao adolescente que:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 13.010, de 2014","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
