      caput: "Entende-se por família natural a comunidade formada pelos pais ou qualquer deles e seus descendentes.",
      paragrafos: [{"id":"eca:art-25-púnico","numero":"único","texto":"Entende-se por família extensa ou ampliada aquela que se estende para além da unidade pais e filhos ou da unidade do casal, formada por parentes próximos com os quais a criança ou adolescente convive e mantém vínculos de afinidade e afetividade.  Vigência","alineas":[]}],
