    {
      tipo: "artigo" as const,
      id: "eca:art-52-B",
      numero: "52-B",
      caput: "A adoção por brasileiro residente no exterior em país ratificante da Convenção de Haia, cujo processo de adoção tenha sido processado em conformidade com a legislação vigente no país de residência e atendido o disposto na Alínea c do Artigo 17 da referida Convenção, será automaticamente recepcionada com o reingresso no Brasil.  Vigência",
      paragrafos: [{"id":"eca:art-52-B-p1","numero":"1","texto":"o Caso não tenha sido atendido o disposto na Alínea c do Artigo 17 da Convenção de Haia, deverá a sentença ser homologada pelo Superior Tribunal de Justiça.  Vigência","alineas":[]},{"id":"eca:art-52-B-p2","numero":"2","texto":"o O pretendente brasileiro residente no exterior em país não ratificante da Convenção de Haia, uma vez reingressado no Brasil, deverá requerer a homologação da sentença estrangeira pelo Superior Tribunal de Justiça.  Vigência","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"A adoção por brasileiro residente no exterior em país ratificante da Convenção de Haia, cujo processo de adoção tenha sido processado em conformidade com a legislação vigente no país de residência e atendido o disposto na Alínea c do Artigo 17 da referida Convenção, será automaticamente recepcionada com o reingresso no Brasil.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o Caso não tenha sido atendido o disposto na Alínea c do Artigo 17 da Convenção de Haia, deverá a sentença ser homologada pelo Superior Tribunal de Justiça.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: o O pretendente brasileiro residente no exterior em país não ratificante da Convenção de Haia, uma vez reingressado no Brasil, deverá requerer a homologação da sentença estrangeira pelo Superior Tribunal de Justiça.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    },
    {
      tipo: "artigo" as const,
      id: "eca:art-52-C",
      numero: "52-C",
      caput: "Nas adoções internacionais, quando o Brasil for o país de acolhida, a decisão da autoridade competente do país de origem da criança ou do adolescente será conhecida pela Autoridade Central Estadual que tiver processado o pedido de habilitação dos pais adotivos, que comunicará o fato à Autoridade Central Federal e determinará as providências necessárias à expedição do Certificado de Naturalização Provisório.  Vigência",
      paragrafos: [{"id":"eca:art-52-C-p1","numero":"1","texto":"o A Autoridade Central Estadual, ouvido o Ministério Público, somente deixará de reconhecer os efeitos daquela decisão se restar demonstrado que a adoção é manifestamente contrária à ordem pública ou não atende ao interesse superior da criança ou do adolescente.  Vigência","alineas":[]},{"id":"eca:art-52-C-p2","numero":"2","texto":"o Na hipótese de não reconhecimento da adoção, prevista no § 1 o deste artigo, o Ministério Público deverá imediatamente requerer o que for de direito para resguardar os interesses da criança ou do adolescente, comunicando-se as providências à Autoridade Central Estadual, que fará a comunicação à Autoridade Central Federal Brasileira e à Autoridade Central do país de origem.  Vigência","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"Nas adoções internacionais, quando o Brasil for o país de acolhida, a decisão da autoridade competente do país de origem da criança ou do adolescente será conhecida pela Autoridade Central Estadual que tiver processado o pedido de habilitação dos pais adotivos, que comunicará o fato à Autoridade Central Federal e determinará as providências necessárias à expedição do Certificado de Naturalização Provisório.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o A Autoridade Central Estadual, ouvido o Ministério Público, somente deixará de reconhecer os efeitos daquela decisão se restar demonstrado que a adoção é manifestamente contrária à ordem pública ou não atende ao interesse superior da criança ou do adolescente.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: o Na hipótese de não reconhecimento da adoção, prevista no § 1 o deste artigo, o Ministério Público deverá imediatamente requerer o que for de direito para resguardar os interesses da criança ou do adolescente, comunicando-se as providências à Autoridade Central Estadual, que fará a comunicação à Autoridade Central Federal Brasileira e à Autoridade Central do país de origem.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
