      caput: "Os dirigentes de estabelecimentos de ensino fundamental comunicarão ao Conselho Tutelar os casos de:",
      paragrafos: [],
      incisos: [{"id":"eca:art-56-inc-I","numero":"I","texto":"maus-tratos envolvendo seus alunos;","alineas":[]},{"id":"eca:art-56-inc-II","numero":"II","texto":"reiteração de faltas injustificadas e de evasão escolar, esgotados os recursos escolares;","alineas":[]},{"id":"eca:art-56-inc-III","numero":"III","texto":"elevados níveis de repetência.","alineas":[]}],
