      caput: "A formação técnico-profissional obedecerá aos seguintes princípios:",
      paragrafos: [],
      incisos: [{"id":"eca:art-63-inc-I","numero":"I","texto":"garantia de acesso e freqüência obrigatória ao ensino regular;","alineas":[]},{"id":"eca:art-63-inc-II","numero":"II","texto":"atividade compatível com o desenvolvimento do adolescente;","alineas":[]},{"id":"eca:art-63-inc-III","numero":"III","texto":"horário especial para o exercício das atividades.","alineas":[]}],
