      paragrafos: [{"id":"eca:art-83-p1","numero":"1","texto":"A autorização não será exigida quando:","alineas":[{"id":"eca:art-83-p1-a","numero":"a","texto":"tratar-se de comarca contígua à da residência da criança ou do adolescente menor de 16 (dezesseis) anos, se na mesma unidade da Federação, ou incluída na mesma região metropolitana;"},{"id":"eca:art-83-p1-b","numero":"b","texto":"a criança ou o adolescente menor de 16 (dezesseis) anos estiver acompanhado:"}]},{"id":"eca:art-83-p2","numero":"2","texto":"A autoridade judiciária poderá, a pedido dos pais ou responsável, conceder autorização válida por dois anos.","alineas":[]}],
