      incisos: [{"id":"eca:art-88-inc-I","numero":"I","texto":"municipalização do atendimento;","alineas":[]},{"id":"eca:art-88-inc-II","numero":"II","texto":"criação de conselhos municipais, estaduais e nacional dos direitos da criança e do adolescente, órgãos deliberativos e controladores das ações em todos os níveis, assegurada a participação popular paritária por meio de organizações representativas, segundo leis federal, estaduais e municipais;","alineas":[]},{"id":"eca:art-88-inc-III","numero":"III","texto":"criação e manutenção de programas específicos, observada a descentralização político-administrativa;","alineas":[]},{"id":"eca:art-88-inc-IV","numero":"IV","texto":"manutenção de fundos nacional, estaduais e municipais vinculados aos respectivos conselhos dos direitos da criança e do adolescente;","alineas":[]},{"id":"eca:art-88-inc-V","numero":"V","texto":"integração operacional de órgãos do Judiciário, Ministério Público, Defensoria, Segurança Pública e Assistência Social, preferencialmente em um mesmo local, para efeito de agilização do atendimento inicial a adolescente a quem se atribua autoria de ato infracional;","alineas":[]},{"id":"eca:art-88-inc-VI","numero":"VI","texto":"integração operacional de órgãos do Judiciário, Ministério Público, Defensoria, Conselho Tutelar e encarregados da execução das políticas sociais básicas e de assistência social, para efeito de agilização do atendimento de crianças e de adolescentes inseridos em programas de acolhimento familiar ou institucional, com vista na sua rápida reintegração à família de origem ou, se tal solução se mostrar comprovadamente inviável, sua colocação em família substituta, em quaisquer das modalidades previstas no art. 28 desta Lei;  Vigência","alineas":[]},{"id":"eca:art-88-inc-VII","numero":"VII","texto":"mobilização da opinião pública para a indispensável participação dos diversos segmentos da sociedade.  Vigência","alineas":[]},{"id":"eca:art-88-inc-VIII","numero":"VIII","texto":"especialização e formação continuada dos profissionais que trabalham nas diferentes áreas da atenção à primeira infância, incluindo os conhecimentos sobre direitos da criança e sobre desenvolvimento infantil;","alineas":[]},{"id":"eca:art-88-inc-IX","numero":"IX","texto":"formação profissional com abrangência dos diversos direitos da criança e do adolescente que favoreça a intersetorialidade no atendimento da criança e do adolescente e seu desenvolvimento integral;","alineas":[]},{"id":"eca:art-88-inc-X","numero":"X","texto":"realização e divulgação de pesquisas sobre desenvolvimento infantil e sobre prevenção da violência.","alineas":[]}],
      referencias: [],
