      historico: [{"versao":1,"texto":"O Ministério Público poderá requerer a instauração de procedimento para apuração de responsabilidades se constatar o descumprimento das providências e do prazo previstos nos artigos anteriores.  Vigência","redacaoDadaPor":{"lei":"Incluído pela Lei nº 12.010, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
